class VectorDBWithMetadata:
    def __init__(self):
        # Store vectors alongside rigid metadata
        self.data = [
            {'id': 1, 'text': 'Apple unveils new AI chips...', 'meta': {'company': 'Apple', 'year': 2022}},
            {'id': 2, 'text': 'Google releases Gemini models', 'meta': {'company': 'Google', 'year': 2024}},
            {'id': 3, 'text': 'Google updates Search algorithm', 'meta': {'company': 'Google', 'year': 2023}}
        ]

    def search(self, query, filters=None):
        results = []
        for doc in self.data:
            # 1. Apply Hard Metadata Filters First
            if filters:
                match = True
                for key, required_val in filters.items():
                    if doc['meta'].get(key) != required_val:
                        match = False
                        break
                if not match:
                    continue

            # 2. Perform Semantic Search (Simulated)
            if query.lower() in doc['text'].lower() or 'ai' in doc['text'].lower():
                results.append(doc['text'])

        return results

db = VectorDBWithMetadata()
# Query asks for AI news, but strictly filtered to Google in 2024
print(db.search('AI models', filters={'company': 'Google', 'year': 2024}))
# Output: ['Google releases Gemini models']
